24	const COMPONENT_TYPES = ["rune", "moonstone"];
25	const COMPONENTS_PER_BLOCK = 3;
26	const COMPONENT_BLOCK_BASE = 60;
27	const COMPONENT_BLOCK_DISCOUNT = COMPONENT_BLOCK_BASE - COMPONENTS_PER_BLOCK * 25;
28	
29	export function quote(_customer: Customer, items: Item[]): number {
30	  const baseSum = items.reduce((sum, item) => sum + BASE_PREMIUMS[item.type], 0);
31	  // A block of exactly COMPONENTS_PER_BLOCK alike components (same type) replaces their summed base with COMPONENT_BLOCK_BASE.
32	  let blockAdjustment = 0;
33	  for (const componentType of COMPONENT_TYPES) {
34	    const count = items.filter((item) => item.type === componentType).length;
35	    if (count === COMPONENTS_PER_BLOCK) {
36	      blockAdjustment += COMPONENT_BLOCK_DISCOUNT;
37	    }
38	  }
39	  const adjustedBase = baseSum + blockAdjustment;
40	  const firstInsurance = adjustedBase * FIRST_INSURANCE_RATE;
41	  return Math.ceil(adjustedBase + firstInsurance + PROCESSING_FEE);
42	}
